import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Upload, Map as MapIcon, Activity, Calendar, AlertCircle, FileText, MapPin, Navigation, Clock, X, CheckCircle, Code, MousePointerClick, Filter, Download, ChevronDown, Eye, EyeOff, LocateFixed, RotateCcw, ChevronLeft, ChevronRight, CircleDot, CalendarDays, Info, Layers, Database, Terminal, RefreshCw } from 'lucide-react';

/**
 * --- UNIVERSAL TRAJECTORY ENGINE V7.2 (RESIZE OBSERVER) ---
 * 1. Fix: Added ResizeObserver to auto-fix map dimensions on layout changes.
 * 2. Fix: Stabilized map initialization to prevent "blank canvas" syndrome.
 * 3. Enhancement: Smoother tab switching logic.
 */

// --- 1. HELPERS & CONFIG ---

const ACTIVITY_STYLES = {
    'DRIVING': { color: '#3B82F6', label: 'Driving' },      
    'WALKING': { color: '#10B981', label: 'Walking' },      
    'RUNNING': { color: '#F59E0B', label: 'Running' },      
    'CYCLING': { color: '#8B5CF6', label: 'Cycling' },      
    'TRAIN':   { color: '#EC4899', label: 'Train' },   
    'BUS':     { color: '#EF4444', label: 'Bus' },          
    'FERRY':   { color: '#06B6D4', label: 'Ferry' },        
    'FLYING':  { color: '#6366F1', label: 'Flying' },       
    'RAW_PATH':{ color: '#64748B', label: 'Raw Path' },     
    'UNKNOWN': { color: '#94A3B8', label: 'Travel' }        
};

const safeGetStyle = (type) => {
    const t = type || 'UNKNOWN';
    return ACTIVITY_STYLES[t] || ACTIVITY_STYLES['UNKNOWN'];
};

const formatDuration = (ms) => {
    if (!ms || isNaN(ms)) return "0m";
    const hours = Math.floor(ms / 3600000);
    const minutes = Math.floor((ms % 3600000) / 60000);
    if (hours > 0) return `${hours}h ${minutes}m`;
    return `${minutes}m`;
};

const parseGeo = (input) => {
    if (!input) return null;

    let lat = null, lng = null;

    if (typeof input === 'string' && input.startsWith('geo:')) {
        const parts = input.replace('geo:', '').split(',');
        if (parts.length === 2) {
            lat = parseFloat(parts[0]);
            lng = parseFloat(parts[1]);
        }
    } else if (typeof input === 'object') {
        if (input.latitudeE7 !== undefined || input.latE7 !== undefined) {
            lat = (input.latitudeE7 ?? input.latE7) / 1e7;
            lng = (input.longitudeE7 ?? input.lngE7) / 1e7;
        } else if (input.latitude !== undefined || input.lat !== undefined) {
            lat = input.latitude ?? input.lat;
            lng = input.longitude ?? input.lng;
        }
    }

    if (lat === null || lng === null || !Number.isFinite(lat) || !Number.isFinite(lng)) return null;
    if (Math.abs(lat) < 0.0001 && Math.abs(lng) < 0.0001) return null; 

    return { lat, lng };
};

const parseTime = (obj) => {
    let start = null, end = null;

    const parseTs = (val) => {
        if (!val) return null;
        if (typeof val === 'string' && /^\d+$/.test(val)) return new Date(parseInt(val));
        return new Date(val);
    };

    if (obj?.timestamp) start = parseTs(obj.timestamp);
    else if (obj?.duration?.startTimestamp) start = new Date(obj.duration.startTimestamp);
    else if (obj?.startTime) start = new Date(obj.startTime);

    if (obj?.duration?.endTimestamp) end = new Date(obj.duration.endTimestamp);
    else if (obj?.endTime) end = new Date(obj.endTime);

    if (start && !end) end = start;

    if (start && isNaN(start.getTime())) start = null;
    if (end && isNaN(end.getTime())) end = null;

    return { start, end, durationMs: (start && end) ? end - start : 0 };
};

const normalizeActivityType = (rawType) => {
    const t = String(rawType || 'UNKNOWN').toUpperCase().replace('_', ' ');
    if (['IN PASSENGER VEHICLE', 'PASSENGER VEHICLE', 'IN CAR', 'DRIVING', 'MOTORCYCLING', 'CAR', 'MOVING'].includes(t)) return 'DRIVING';
    if (['IN TRAIN', 'TRAIN', 'SUBWAY', 'TRAM', 'RAIL'].includes(t)) return 'TRAIN';
    if (['IN BUS', 'BUS'].includes(t)) return 'BUS';
    if (['IN FERRY', 'FERRY', 'BOAT'].includes(t)) return 'FERRY';
    if (['FLYING', 'IN FLIGHT', 'PLANE', 'AIR'].includes(t)) return 'FLYING';
    if (['WALKING', 'ON FOOT', 'HIKING', 'RUNNING'].includes(t)) return 'WALKING';
    if (['CYCLING', 'ON BICYCLE'].includes(t)) return 'CYCLING';
    return 'UNKNOWN';
};

// --- 3. PARSER LOGIC ---

const detectAndNormalize = (json) => {
    let rawItems = [];
    let formatType = "Unknown";

    if (json.locations && Array.isArray(json.locations)) {
        rawItems = json.locations;
        formatType = "Raw GPS (Records.json)";
    } else if (Array.isArray(json)) {
        rawItems = json;
        formatType = "Flat Array / New Semantic";
    } else if (json.timelineObjects) {
        rawItems = json.timelineObjects;
        formatType = "Standard Timeline";
    } else {
        const vals = Object.values(json);
        const arr = vals.find(v => Array.isArray(v));
        if (arr) { rawItems = arr; formatType = "Inferred Array"; }
    }

    if (rawItems.length === 0) throw new Error("No data found in file.");

    // PASS 1: Index High-Res Paths
    const timelinePaths = [];
    rawItems.forEach(item => {
        if (item.timelinePath && Array.isArray(item.timelinePath)) {
            const time = parseTime(item);
            const points = item.timelinePath.map(p => p.point || p).map(parseGeo).filter(p => p);
            if (points.length > 0) {
                timelinePaths.push({
                    startTime: time.start,
                    endTime: time.end,
                    points: points,
                    raw: item,
                    claimed: false
                });
            }
        }
    });

    // PASS 2: Build Activities & Visits
    const normalized = [];
    const stats = { format: formatType, activityCounts: {} };
    const uniqueDays = new Set();

    const getLocalDate = (dateObj) => {
        if(!dateObj) return 'UNKNOWN';
        return dateObj.getFullYear() + '-' + 
               String(dateObj.getMonth() + 1).padStart(2, '0') + '-' + 
               String(dateObj.getDate()).padStart(2, '0');
    };

    rawItems.forEach((item, index) => {
        const act = item.activity || item.activitySegment;
        const visit = item.visit || item.placeVisit;

        if (visit) {
             const time = parseTime(visit, item.startTime, item.endTime) || parseTime(item);
             let name = "Unknown Place", loc = null;
             if (visit.topCandidate) {
                 name = visit.topCandidate.semanticType || visit.topCandidate.placeID || "Place";
                 loc = parseGeo(visit.topCandidate.placeLocation);
             } else if (visit.location) {
                 name = visit.location.name || visit.location.address || "Place";
                 loc = parseGeo(visit.location);
             }
             if (loc && time.start) {
                 const dateStr = getLocalDate(time.start);
                 uniqueDays.add(dateStr);
                 normalized.push({
                     id: `place-${index}`, type: 'PLACE', name: String(name), lat: loc.lat, lng: loc.lng,
                     startTime: time.start, endTime: time.end, duration: time.durationMs, raw: item,
                     dateStr: dateStr
                 });
             }
        }

        if (act) {
            const rawType = act?.topCandidate?.type || act?.activityType;
            const type = normalizeActivityType(rawType);
            const time = parseTime(act, item.startTime, item.endTime) || parseTime(item);

            if (time.start) {
                const dateStr = getLocalDate(time.start);
                uniqueDays.add(dateStr);

                let path = [];
                if (act.simplifiedRawPath?.points) path = act.simplifiedRawPath.points.map(parseGeo);
                else if (act.waypointPath?.waypoints) path = act.waypointPath.waypoints.map(parseGeo);
                else if (act.transitPath?.transitStops) path = act.transitPath.transitStops.map(s => s.location).map(parseGeo);

                // Enrich
                if (path.length < 2) {
                    const relevantPaths = timelinePaths.filter(tp => 
                        !tp.claimed && tp.startTime && tp.endTime && time.start && time.end &&
                        ((tp.startTime >= time.start && tp.startTime < time.end) || 
                         (tp.endTime > time.start && tp.endTime <= time.end) ||
                         (tp.startTime <= time.start && tp.endTime >= time.end))
                    );

                    if (relevantPaths.length > 0) {
                        path = [];
                        relevantPaths.forEach(rp => {
                            path = [...path, ...rp.points];
                            rp.claimed = true;
                        });
                    }
                }

                path = path.filter(p => p);
                const startLoc = parseGeo(act?.start || act?.startLocation) || path[0];
                const endLoc = parseGeo(act?.end || act?.endLocation) || path[path.length-1];

                normalized.push({
                    id: `act-${index}`,
                    type: 'ACTIVITY',
                    subType: type,
                    distance: parseFloat(act?.distanceMeters || act?.distance || 0),
                    duration: time.durationMs,
                    startTime: time.start,
                    endTime: time.end,
                    startLoc,
                    endLoc,
                    path,
                    isDetailed: path.length > 0,
                    raw: item,
                    dateStr: dateStr
                });
            }
        }
    });

    // PASS 3: Fallback
    timelinePaths.forEach((tp, i) => {
        if (!tp.claimed && tp.startTime) {
             const dateStr = getLocalDate(tp.startTime);
             uniqueDays.add(dateStr);
             normalized.push({
                id: `tl-path-${i}`,
                type: 'ACTIVITY',
                subType: 'RAW_PATH',
                distance: 0, 
                duration: (tp.endTime && tp.startTime) ? tp.endTime - tp.startTime : 0,
                startTime: tp.startTime,
                endTime: tp.endTime,
                path: tp.points,
                isDetailed: true,
                raw: tp.raw,
                isFallback: true,
                dateStr: dateStr
             });
        }
    });

    normalized.sort((a, b) => (a.startTime || 0) - (b.startTime || 0));

    normalized.forEach(item => {
        const key = item.type === 'PLACE' ? 'PLACES' : item.subType;
        stats.activityCounts[key] = (stats.activityCounts[key] || 0) + 1;
    });

    return { items: normalized, meta: stats, availableDates: Array.from(uniqueDays).sort() };
};


// --- 4. MAIN DASHBOARD ---

const Dashboard = () => {
  const [data, setData] = useState(null);
  const [meta, setMeta] = useState(null);
  const [fileName, setFileName] = useState(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('overview');
  const [focusedItem, setFocusedItem] = useState(null);
  const [inspectItem, setInspectItem] = useState(null); 

  const [availableDates, setAvailableDates] = useState([]);
  const [selectedDates, setSelectedDates] = useState(new Set());
  const [activityFilters, setActivityFilters] = useState({});
  const [spatialFilter, setSpatialFilter] = useState(null); 
  const [showFilterMenu, setShowFilterMenu] = useState(false);
  const [showCalendar, setShowCalendar] = useState(false);
  const [showDots, setShowDots] = useState(true);
  const [showLogs, setShowLogs] = useState(false);
  const [filterListByView, setFilterListByView] = useState(false);
  const [isLeafletLoaded, setIsLeafletLoaded] = useState(false);

  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const resizeObserverRef = useRef(null);

  // --- Leaflet Init & Resize Observer ---
  useEffect(() => {
      if (window.L && window.L.map) { setIsLeafletLoaded(true); return; }
      const link = document.createElement('link'); link.rel = 'stylesheet'; link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css'; document.head.appendChild(link);
      const script = document.createElement('script'); script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js'; script.async = true;
      script.onload = () => { setTimeout(() => { if (window.L && window.L.map) setIsLeafletLoaded(true); }, 200); };
      document.head.appendChild(script);
  }, []);

  // Initialize ResizeObserver whenever mapRef changes
  useEffect(() => {
      if (!mapRef.current || !mapInstanceRef.current) return;

      // Setup Observer
      resizeObserverRef.current = new ResizeObserver(() => {
          if (mapInstanceRef.current) {
              mapInstanceRef.current.invalidateSize();
          }
      });

      resizeObserverRef.current.observe(mapRef.current);

      return () => {
          if (resizeObserverRef.current) resizeObserverRef.current.disconnect();
      };
  }, [activeTab, isLeafletLoaded]); // Re-run when tab changes to re-attach observer

  const filteredData = useMemo(() => {
      if (!data) return [];
      return data.filter(item => {
          if (selectedDates.size > 0 && !selectedDates.has(item.dateStr)) return false;
          const key = item.type === 'PLACE' ? 'PLACES' : item.subType;
          if (activityFilters[key] === false) return false;

          const bounds = spatialFilter || (filterListByView && mapInstanceRef.current ? mapInstanceRef.current.getBounds() : null);
          if (bounds) {
              if (item.type === 'PLACE' || item.type === 'RAW_POINT') return bounds.contains([item.lat, item.lng]);
              if (item.type === 'ACTIVITY') {
                  const s = item.startLoc ? bounds.contains([item.startLoc.lat, item.startLoc.lng]) : false;
                  const e = item.endLoc ? bounds.contains([item.endLoc.lat, item.endLoc.lng]) : false;
                  const p = item.path ? item.path.some(pt => bounds.contains([pt.lat, pt.lng])) : false;
                  return s || e || p;
              }
          }
          return true;
      });
  }, [data, selectedDates, activityFilters, spatialFilter, filterListByView]);

  const currentStats = useMemo(() => {
      const stats = { dist: 0, time: 0, items: 0, detailedPaths: 0 };
      filteredData.forEach(d => {
          stats.items++;
          if (d.duration) stats.time += d.duration;
          if (d.type === 'ACTIVITY') {
              stats.dist += (d.distance || 0);
              if (d.isDetailed) stats.detailedPaths++;
          }
      });
      return stats;
  }, [filteredData]);

  const handleFileUpload = (event) => {
    const file = event.target.files[0];
    if (!file) return;
    setLoading(true); setFileName(file.name);
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const json = JSON.parse(e.target.result);
            const res = detectAndNormalize(json);
            setData(res.items);
            setMeta(res.meta);
            setAvailableDates(res.availableDates);

            if (res.availableDates.length > 0) {
                const lastDate = res.availableDates[res.availableDates.length - 1];
                const lastCount = res.items.filter(i => i.dateStr === lastDate).length;

                if (lastCount > 0) setSelectedDates(new Set([lastDate]));
                else setSelectedDates(new Set());
            } else {
                setSelectedDates(new Set());
            }

            const types = {};
            Object.keys(res.meta.activityCounts).forEach(k => types[k] = true);
            setActivityFilters(types);
            setLoading(false);
        } catch (err) {
            alert("Error: " + err.message);
            setLoading(false);
        }
    };
    reader.readAsText(file);
  };

  const toggleDate = (date) => {
      if (date === 'ALL') setSelectedDates(new Set());
      else if (date === 'CLEAR') setSelectedDates(new Set());
      else {
          const newSet = new Set(selectedDates);
          if (newSet.has(date)) newSet.delete(date);
          else newSet.add(date);
          setSelectedDates(newSet);
      }
  };

  const forceResize = () => {
      if (mapInstanceRef.current) mapInstanceRef.current.invalidateSize();
  };

  // --- MAP RENDER LOGIC ---
  useEffect(() => {
      // Cleanup if leaving map
      if (activeTab !== 'map' && mapInstanceRef.current) {
          mapInstanceRef.current.remove();
          mapInstanceRef.current = null;
          return;
      }

      if (activeTab !== 'map' || !mapRef.current || !isLeafletLoaded) return;
      if (typeof window.L === 'undefined') return;

      // Init Map
      if (!mapInstanceRef.current) {
          mapInstanceRef.current = window.L.map(mapRef.current);
          window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { 
              attribution: '© OpenStreetMap' 
          }).addTo(mapInstanceRef.current);

          mapInstanceRef.current.on('moveend', () => {
              setFilterListByView(prev => prev ? (setSpatialFilter(null) || prev) : prev);
          });
      }

      const map = mapInstanceRef.current;

      // Immediate resize
      map.invalidateSize();

      // Clear Layers
      map.eachLayer(l => { if (!l._url) map.removeLayer(l); });

      const bounds = window.L.latLngBounds();
      let hasLayers = false;
      let globalPointCounter = 1;

      filteredData.forEach(item => {
          if (item.type === 'PLACE') {
              window.L.circleMarker([item.lat, item.lng], {
                  radius: 7, color: '#fff', fillColor: '#EF4444', fillOpacity: 1, weight: 2
              }).bindPopup(`<b>${item.name}</b><br/>${item.startTime.toLocaleTimeString()}`).addTo(map);
              bounds.extend([item.lat, item.lng]);
              hasLayers = true;
          } 
          else if (item.type === 'ACTIVITY') {
              const style = safeGetStyle(item.subType);
              let latlngs = [];

              if (item.path && item.path.length > 0) {
                  latlngs = item.path;
                  window.L.polyline(latlngs, { color: style.color, weight: 4, opacity: 0.8, lineCap: 'round' }).addTo(map);
                  if (showDots) {
                      latlngs.forEach((p) => {
                          window.L.circleMarker([p.lat, p.lng], { 
                              radius: 3, color: style.color, fillColor: '#fff', fillOpacity: 1, weight: 1 
                          }).bindTooltip(`${globalPointCounter++}`, {
                              permanent: true, direction: 'right', className: 'bg-transparent border-0 shadow-none text-xs font-bold text-slate-600'
                          }).addTo(map);
                      });
                  }
              } else if (item.startLoc && item.endLoc) {
                  latlngs = [item.startLoc, item.endLoc];
                  window.L.polyline(latlngs, { color: style.color, weight: 3, opacity: 0.6, dashArray: '5, 10' }).addTo(map);
              }

              if (latlngs.length > 0) {
                  latlngs.forEach(p => bounds.extend([p.lat, p.lng]));
                  hasLayers = true;
              }
          }
      });

      if (spatialFilter) window.L.rectangle(spatialFilter, {color: "#10B981", weight: 2, fill: false, dashArray: '5, 10'}).addTo(map);

      if (hasLayers && !focusedItem && !spatialFilter && bounds.isValid()) {
          map.fitBounds(bounds, { padding: [50, 50] });
      }
      else if (focusedItem) {
          const lat = focusedItem.lat || focusedItem.startLoc?.lat;
          const lng = focusedItem.lng || focusedItem.startLoc?.lng;
          if(lat && lng) map.setView([lat, lng], 15);
      }

  }, [activeTab, filteredData, showDots, focusedItem, isLeafletLoaded, spatialFilter]);

  if (!data) return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="bg-white p-8 rounded-xl shadow-lg max-w-lg w-full text-center border border-slate-200">
          <div className="bg-blue-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6"><MapIcon className="w-8 h-8 text-blue-600" /></div>
          <h1 className="text-2xl font-bold text-slate-900 mb-2">Timeline Visualizer V7.2</h1>
          <p className="text-slate-600 mb-6 text-sm">Auto-Resizing Map Fix applied.</p>
          <div className="border-2 border-dashed border-slate-300 rounded-lg p-8 bg-slate-50 hover:bg-slate-100 relative cursor-pointer">
            <input type="file" accept=".json" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
            <Upload className="w-10 h-10 text-slate-400 mx-auto mb-2" />
            <p className="font-medium text-slate-700">Upload JSON</p>
          </div>
          {loading && <div className="mt-4 text-blue-600 flex items-center justify-center"><Clock className="animate-spin mr-2 w-4 h-4"/> Processing...</div>}
        </div>
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Custom Mini Calendar */}
      {showCalendar && (
          <div className="fixed inset-0 z-[2000] flex items-start justify-center pt-32" onClick={() => setShowCalendar(false)}>
             <div className="bg-white rounded-xl shadow-2xl p-4 w-80 border border-slate-200" onClick={e => e.stopPropagation()}>
                 <div className="font-bold text-slate-800 mb-4 flex justify-between">
                    <span>Select Date</span>
                    <button onClick={() => setShowCalendar(false)}><X className="w-4 h-4 text-slate-400"/></button>
                 </div>
                 <div className="max-h-64 overflow-y-auto grid grid-cols-4 gap-2">
                    {availableDates.map(d => (
                        <button key={d} onClick={() => {toggleDate(d); setShowCalendar(false);}} className={`text-xs p-2 rounded ${selectedDates.has(d) ? 'bg-blue-600 text-white' : 'bg-slate-100 hover:bg-blue-50 text-slate-700'}`}>
                            {d.slice(5)}
                        </button>
                    ))}
                 </div>
                 <div className="mt-4 pt-3 border-t border-slate-100 flex justify-between text-xs">
                     <button onClick={() => toggleDate('ALL')} className="text-blue-600 hover:underline">Show All</button>
                     <button onClick={() => toggleDate('CLEAR')} className="text-slate-500 hover:text-slate-700">Clear</button>
                 </div>
             </div>
          </div>
      )}

      {/* Data Inspector */}
      {inspectItem && (
        <div className="fixed inset-0 bg-black/50 z-[2000] flex items-center justify-center p-6" onClick={() => setInspectItem(null)}>
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
                <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                    <h3 className="font-bold text-slate-800">Raw Data Inspector</h3>
                    <button onClick={() => setInspectItem(null)}><X className="w-5 h-5 text-slate-500"/></button>
                </div>
                <div className="flex-1 overflow-auto p-4 bg-slate-900 text-slate-300 font-mono text-xs">
                    <pre>{JSON.stringify(inspectItem.raw, null, 2)}</pre>
                </div>
            </div>
        </div>
      )}

      <header className="bg-white border-b border-slate-200 px-6 py-3 shadow-sm z-[1000] relative h-[64px]">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-green-100 p-2 rounded-md"><CheckCircle className="w-5 h-5 text-green-600"/></div>
                <div><h1 className="font-bold text-slate-800">Timeline Analysis</h1></div>
            </div>

            <div className="flex items-center gap-4">
                 <button onClick={() => setShowCalendar(true)} className="flex items-center bg-slate-50 hover:bg-slate-100 border border-slate-200 px-3 py-2 rounded-lg text-sm font-medium transition-colors">
                    <Calendar className="w-4 h-4 mr-2 text-blue-600" />
                    {selectedDates.size === 0 ? "All History" : `${selectedDates.size} Days`}
                    <ChevronDown className="w-4 h-4 ml-2 text-slate-400" />
                </button>
                <button onClick={() => setShowLogs(!showLogs)} className="flex items-center gap-1 text-xs font-mono bg-slate-800 text-white px-2 py-1 rounded"><Terminal className="w-3 h-3"/> Logs</button>
                <button onClick={() => setData(null)} className="p-2 text-slate-400 hover:text-red-500"><X className="w-5 h-5"/></button>
            </div>
          </div>
      </header>

      <div className="bg-white border-b px-6 flex gap-8 text-sm font-medium h-[50px]">
        {['overview', 'map', 'list'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`py-3 border-b-2 capitalize ${activeTab === tab ? 'border-blue-600 text-blue-600' : 'border-transparent'}`}>{tab}</button>
        ))}
      </div>

      <main className="bg-slate-100 overflow-hidden relative" style={{ height: 'calc(100vh - 114px)' }}>
         <div className="h-full w-full relative">

            {activeTab === 'map' && (
                <>
                    <div 
                        ref={mapRef} 
                        className="w-full h-full z-0 absolute inset-0" 
                        id="leaflet-map-container"
